/**
 * LINE Webhook 署名検証（n8n Code ノード用）
 * require('crypto') は禁止のため Web Crypto API を使用
 */
const secret = $env.LINE_CHANNEL_SECRET;
if (!secret) {
  throw new Error('環境変数 LINE_CHANNEL_SECRET を設定してください');
}

const item = $input.first().json;
const headers = item.headers || {};
const signature = headers['x-line-signature'] || headers['X-Line-Signature'];

if (!signature) {
  return [{ json: { valid: false, reason: 'missing_signature', events: [] } }];
}

const rawBody = item.rawBody;
let bodyString;

if (typeof rawBody === 'string') {
  bodyString = rawBody;
} else if (typeof Buffer !== 'undefined' && Buffer.isBuffer(rawBody)) {
  bodyString = rawBody.toString('utf8');
} else if (rawBody && rawBody.type === 'Buffer' && Array.isArray(rawBody.data)) {
  bodyString = Buffer.from(rawBody.data).toString('utf8');
} else {
  bodyString = JSON.stringify(item.body ?? item);
}

async function hmacSha256Base64(key, message) {
  const enc = new TextEncoder();
  const cryptoKey = await crypto.subtle.importKey(
    'raw',
    enc.encode(key),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  const sig = await crypto.subtle.sign('HMAC', cryptoKey, enc.encode(message));
  const bytes = new Uint8Array(sig);
  let binary = '';
  bytes.forEach((b) => {
    binary += String.fromCharCode(b);
  });
  return btoa(binary);
}

return (async () => {
  const hash = await hmacSha256Base64(secret, bodyString);
  const valid = hash === signature;

  let payload = {};
  try {
    payload = JSON.parse(bodyString);
  } catch {
    payload = item.body ?? item;
  }

  return [
    {
      json: {
        valid,
        reason: valid ? 'ok' : 'invalid_signature',
        events: payload.events || [],
        destination: payload.destination ?? null,
      },
    },
  ];
})();

const events = $json.events || [];
if (events.length === 0) {
  return [{ json: { skip: true, reason: 'no_events' } }];
}

const TZ = 'Asia/Tokyo';
const now = new Date();
const jst = new Date(now.toLocaleString('en-US', { timeZone: TZ }));
const day = jst.getDay(); // 0=日
const hour = jst.getHours();
const minute = jst.getMinutes();
const minutes = hour * 60 + minute;

function isOpen() {
  if (day === 0) return false; // 日曜
  // 祝日は未対応（Google Calendar 連携で拡張可）
  if ([1, 2, 3, 5].includes(day)) {
    return minutes >= 9 * 60 && minutes < 18 * 60;
  }
  if ([4, 6].includes(day)) {
    return minutes >= 9 * 60 && minutes < 13 * 60;
  }
  return false;
}

const open = isOpen();

const MSG = {
  welcome: `エイト薬局の公式LINEへようこそ。

処方せんの送信やお薬のご相談は、このトークからお気軽にどうぞ。

【営業時間】
月・火・水・金 9:00〜18:00
木・土 9:00〜13:00
定休日 日曜・祝日

【お電話】03-6271-6284`,
  prescription: `処方せんのご送付ありがとうございます。

お写真をそのままお送りいただくか、ご来院時に処方せんをお渡しください。内容を確認のうえ、ご連絡いたします。

お急ぎの方は 03-6271-6284 までお電話ください。`,
  consult: `お薬に関するご相談ありがとうございます。

症状やお薬の名前、ご不明点をメッセージでお送りください。担当薬剤師が確認してご返信いたします。`,
  hours: `【営業時間】
月・火・水・金 9:00〜18:00
木・土 9:00〜13:00
定休日 日曜・祝日

【所在地】
〒143-0012
東京都大田区大森東1-4-5 サワビル1階

【TEL】03-6271-6284`,
  image: `画像を受け取りました。ありがとうございます。

処方せんの可能性がある場合は、担当者が確認いたします。しばらくお待ちください。`,
  default: `お問い合わせありがとうございます。

担当者が確認次第、ご返信いたします。
お急ぎの方はお電話ください。

☎ 03-6271-6284`,
  closed: `現在、営業時間外です。

【営業時間】
月・火・水・金 9:00〜18:00
木・土 9:00〜13:00
定休日 日曜・祝日

メッセージは確認し、営業開始後にご返信いたします。
お急ぎの方は 03-6271-6284 までお電話ください。`
};

function pickReply(event) {
  const type = event.type;
  const replyToken = event.replyToken;
  const userId = event.source?.userId || 'unknown';

  if (!replyToken) {
    return null;
  }

  let text = MSG.default;
  let notifyType = 'general';
  let notifyDetail = '';

  if (type === 'follow') {
    text = MSG.welcome;
    notifyType = 'follow';
  } else if (type === 'message') {
    const msg = event.message || {};
    if (msg.type === 'text') {
      const t = (msg.text || '').trim();
      const lower = t.toLowerCase();
      if (/処方|処方箋|処方せん|shohousen/i.test(t)) {
        text = MSG.prescription;
        notifyType = 'prescription';
        notifyDetail = t;
      } else if (/相談|くすり|薬|飲み方|副作用/.test(t)) {
        text = MSG.consult;
        notifyType = 'consult';
        notifyDetail = t;
      } else if (/営業|時間|休み|定休|開いて|何時/.test(t)) {
        text = MSG.hours;
        notifyType = 'hours';
      } else {
        notifyType = 'message';
        notifyDetail = t;
      }
      if (!open && type === 'message') {
        text = MSG.closed + '\n\n---\n' + text;
      }
    } else if (msg.type === 'image') {
      text = MSG.image;
      notifyType = 'image';
      notifyDetail = msg.id || '';
      if (!open) {
        text = MSG.closed + '\n\n---\n' + text;
      }
    } else {
      notifyType = 'other_message';
      notifyDetail = msg.type || '';
    }
  } else if (type === 'unfollow') {
    return {
      skipReply: true,
      notifyType: 'unfollow',
      userId,
      eventType: type
    };
  } else {
    return null;
  }

  return {
    skipReply: false,
    replyToken,
    userId,
    eventType: type,
    replyText: text,
    notifyType,
    notifyDetail,
    isOpen: open
  };
}

const outputs = [];
for (const event of events) {
  const item = pickReply(event);
  if (item) outputs.push({ json: item });
}

if (outputs.length === 0) {
  return [];
}

return outputs;

